# dual skeptic-H1 · S47-T1-A-E2
def assess(record: dict) -> str:
    required = {'metric', 'rerun_metric', 'tolerance', 'case_id', 'params', 'seed'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = not (abs(record["metric"] - record["rerun_metric"]) > record["tolerance"])
    return "PASS" if ok else 'MARK_RUN_NONREPRODUCIBLE'

valid = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 0.81, 'rerun_metric': 0.805, 'tolerance': 0.01}
invalid = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 0.81, 'rerun_metric': 0.805, 'tolerance': 0.01, '_adverse': True}
incomplete = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 0.81, 'rerun_metric': 0.805}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
# skeptic_check: form+pass contract

